// FIX 2: Safe JSON parse for extractor output
// FIX 1: callerName fallback if extracted name is empty

const raw = $input.item.json.message.content || '';
const callerName = $('Normalise Payload').item.json.callerName || '';

let extracted;
try {
  // Strip markdown code fences if model returns them despite instructions
  const cleaned = raw.replace(/^```[a-z]*\n?/i, '').replace(/```$/,'').trim();
  extracted = JSON.parse(cleaned);
} catch (e) {
  // Fallback: return safe defaults so workflow continues
  extracted = {
    name: callerName,
    phone: '',
    postcode: '',
    serviceType: '',
    issueSummary: 'Could not extract — check transcript manually',
    urgency: 'low',
    preferredTime: '',
    propertyType: 'unknown',
    customerType: 'unknown',
    needsHuman: false,
    emergencyType: 'none',
    outcome: 'no_action'
  };
}

// FIX 1: Use callerName as fallback if extracted name is empty
if (!extracted.name && callerName) {
  extracted.name = callerName;
}

return {
  extracted,
  callId: $('Normalise Payload').item.json.callId,
  waId: $('Normalise Payload').item.json.waId,
  phone: $('Normalise Payload').item.json.phone,
  callerName,
  transcriptText: $('Normalise Payload').item.json.transcriptText
};

// FIX 2: Safe JSON parse for summary output

const raw = $input.item.json.message.content || '';

let teamSummary;
try {
  const cleaned = raw.replace(/^```[a-z]*\n?/i, '').replace(/```$/, '').trim();
  teamSummary = JSON.parse(cleaned);
} catch (e) {
  // Fallback defaults so workflow continues
  teamSummary = {
    summary: 'Summary unavailable — review transcript manually',
    urgency: $('Parse Extracted Fields').item.json.extracted.urgency || 'low',
    serviceType: $('Parse Extracted Fields').item.json.extracted.serviceType || '',
    needsHuman: $('Parse Extracted Fields').item.json.extracted.needsHuman || false,
    qualifiedLead: false
  };
}

return {
  teamSummary,
  extracted: $('Parse Extracted Fields').item.json.extracted,
  callId: $('Parse Extracted Fields').item.json.callId,
  waId: $('Parse Extracted Fields').item.json.waId,
  phone: $('Parse Extracted Fields').item.json.phone
};

